#include <bits/stdc++.h>
using namespace std;

int n, m;
vector<int> c[100005];
bool vis[100005];
int maxn = 0, minn = 0;
int cnt[2];

void find(int x, int p) {
    vis[x] = true;
    cnt[p]++;
    for (int i = 0; i < c[x].size(); i++) {
        if (!vis[c[x][i]]) {
            find(c[x][i], !p);
        }
    }
}

int main() {
    cin >> n >> m;
    for (int i = 0; i < m; i++) {
        int u, v;
        cin >> u >> v;
        c[u].push_back(v);
        c[v].push_back(u);
    }
    for (int i = 1; i <= n; i++) {
        if (!vis[i]) {
            cnt[0] = cnt[1] = 0;
            find(i, 0);
            maxn += max(cnt[0], cnt[1]);
            minn += min(cnt[0], cnt[1]);
        }
    }
    cout << minn << " " << maxn << endl;
    return 0;
}
